def qa_check(name: str, namespace: dict, *args):
    """Run a hidden qa_check function inside the notebook namespace."""
    if name not in _CHECKS:
        raise KeyError(f"Unknown qa_check: {name}")
    exec(_CHECKS[name], namespace)
    return namespace[name](*args)
